// ==============================
// LOW-JITTER MTC GENERATOR
// One function node per zone
// Change ONLY cueListName per copy
// ==============================

// -------- USER SETTINGS --------
const MTC_FPS = 30;              // 24 | 25 | 29.97 | 30
const initial = "00:00:00:00";
const offsetH = 0;
const cueListName = "Zone11";         // CHANGE THIS PER NODE
// -------------------------------

// ---- Timer stored on node object (never serialized) ----
if (node._mtcTimer === undefined) { node._mtcTimer = null; }
if (node._mtcGen === undefined) { node._mtcGen = 0; }

// ---- Global key names (read by other nodes) ----
const zoneTC = "generatingTC" + cueListName;
const zoneTrigTC = "trigTC" + cueListName;
const timecodeName = "timecode" + cueListName;
const framesZone = "frames" + cueListName;
const timestampName = "timestamp" + cueListName;
const msName = "ms" + cueListName;

// ---- Timestamp base ----
const baseYear = 1980;
const baseMonth = 11;   // JS 0-based, kept as original
const baseDay = 1;

// ---- Precomputed constants ----
const MS_PER_FRAME = 1000 / MTC_FPS;
const QF_PERIOD_MS = MS_PER_FRAME / 4;  // one quarter-frame period
const MAX_CATCHUP = 4;                  // cap catch-up burst per tick

// ---- MTC rate bits ----
function getRateBits(fps) {
    if (fps === 24) return 0;
    if (fps === 25) return 1;
    if (fps === 29.97) return 2;
    return 3; // 30 or default
}
const RATE_BITS = getRateBits(MTC_FPS);

// ---- Runtime state (context, never persisted) ----
// These are simple numbers/booleans/arrays — safe to persist,
// but we keep them in context for access across tick() calls.

// ===================================================
//  HELPERS
// ===================================================

function pad2(n) {
    return (n < 10 ? "0" : "") + n;
}

function timecodeFromMs(totalMs) {
    if (totalMs < 0) totalMs = 0;
    const totalSec = Math.floor(totalMs / 1000);
    return {
        hours: Math.floor(totalSec / 3600) + offsetH,
        minutes: Math.floor(totalSec / 60) % 60,
        seconds: totalSec % 60,
        frames: Math.floor((totalMs % 1000) / MS_PER_FRAME)
    };
}

function encodeMtcNibbles(tc) {
    const hh = tc.hours % 24;
    const mm = tc.minutes;
    const ss = tc.seconds;
    const ff = tc.frames;
    return [
        ff & 0x0F,                                              // QF0
        (ff >> 4) & 0x01,                                       // QF1
        ss & 0x0F,                                              // QF2
        (ss >> 4) & 0x03,                                       // QF3
        mm & 0x0F,                                              // QF4
        (mm >> 4) & 0x03,                                       // QF5
        hh & 0x0F,                                              // QF6
        (((RATE_BITS & 0x03) << 1) | ((hh >> 4) & 0x01)) & 0x0F // QF7
    ];
}

// ===================================================
//  GLOBALS WRITER
// ===================================================

function writeGlobals(elapsedMs) {
    global.set(msName, elapsedMs);

    const totalFrameIndex = Math.floor(elapsedMs / MS_PER_FRAME);

    if (totalFrameIndex !== context.get("lastFrameIndex")) {
        context.set("lastFrameIndex", totalFrameIndex);

        const tc = timecodeFromMs(elapsedMs);
        const tcText = pad2(tc.hours) + ":" + pad2(tc.minutes) + ":" +
            pad2(tc.seconds) + ":" + pad2(tc.frames);

        context.set("cachedNibbles", encodeMtcNibbles(tc));

        global.set(timecodeName, tcText);
        global.set(framesZone, totalFrameIndex);

        const msInFrame = Math.round(tc.frames * MS_PER_FRAME);
        const d = new Date(baseYear, baseMonth, baseDay,
            tc.hours, tc.minutes, tc.seconds, msInFrame);
        global.set(timestampName, d.getTime());
    }
}

// ===================================================
//  TIMER MANAGEMENT (on node object, never serialized)
// ===================================================

function clearTimer() {
    if (node._mtcTimer) {
        clearTimeout(node._mtcTimer);
        node._mtcTimer = null;
    }
}

// ===================================================
//  TICK — self-scheduling setTimeout chain
// ===================================================

function tick(gen) {
    if (!context.get("running")) return;

    // Guard against stale tick from a previous chain
    if (gen !== node._mtcGen) return;

    const now = Date.now();
    const startEpochMs = context.get("startEpochMs");
    let qfCounter = context.get("qfCounter");
    let nextDueMs = context.get("nextDueMs");
    const elapsedNow = Math.max(0, now - startEpochMs);

    writeGlobals(elapsedNow);

    // Send quarter-frames, catching up if late (capped)
    let sent = 0;
    const nibbles = context.get("cachedNibbles");

    while (now >= nextDueMs && sent < MAX_CATCHUP && nibbles) {
        const piece = qfCounter % 8;
        node.send({ payload: [0xF1, (piece << 4) | nibbles[piece]] });
        qfCounter++;
        nextDueMs = startEpochMs + (qfCounter * QF_PERIOD_MS);
        sent++;
    }

    context.set("qfCounter", qfCounter);
    context.set("nextDueMs", nextDueMs);

    // Check external triggers
    const trig = global.get(zoneTrigTC);
    if (trig === "stop") { stopGenerator(); return; }
    if (trig === "pause") { pauseGenerator(); return; }

    global.set(zoneTC, "Running");

    // Schedule next tick — pass generation as argument, not via bind/this
    const delay = Math.max(0, Math.round(nextDueMs - Date.now()));
    node._mtcTimer = setTimeout(tick, delay, gen);
}

// ===================================================
//  START / PAUSE / STOP
// ===================================================

function startOrResume(gotoMs) {
    clearTimer();

    // Bump generation — any stale tick sees mismatch and exits
    node._mtcGen++;
    const gen = node._mtcGen;

    const wasPaused = !!context.get("paused");

    // Priority: explicit goto value → context (normal pause) → global ms (flow restart) → 0
    let elapsedBefore;
    if (gotoMs !== undefined) {
        elapsedBefore = Number(gotoMs) || 0;
    } else if (wasPaused) {
        elapsedBefore = Number(context.get("elapsedBeforePause")) || 0;
    } else {
        elapsedBefore = Number(global.get(msName)) || 0;
    }
    const now = Date.now();
    const startEpochMs = now - elapsedBefore;
    const qfCounter = Math.floor(elapsedBefore / QF_PERIOD_MS);

    context.set("running", true);
    context.set("paused", false);
    context.set("startEpochMs", startEpochMs);
    context.set("elapsedBeforePause", 0);
    context.set("qfCounter", qfCounter);
    context.set("nextDueMs", startEpochMs + ((qfCounter + 1) * QF_PERIOD_MS));
    context.set("lastFrameIndex", -1);

    global.set(zoneTrigTC, "start");
    global.set(zoneTC, "Running");
    global.set("fps", MTC_FPS);

    writeGlobals(elapsedBefore);
    tick(gen);
}

function pauseGenerator() {
    if (!context.get("running")) return;

    const elapsedNow = Math.max(0, Date.now() - context.get("startEpochMs"));
    clearTimer();

    context.set("running", false);
    context.set("paused", true);
    context.set("elapsedBeforePause", elapsedNow);

    global.set(zoneTrigTC, "pause");
    global.set(zoneTC, "Paused");
    writeGlobals(elapsedNow);
}

function stopGenerator() {
    clearTimer();

    context.set("running", false);
    context.set("paused", false);
    context.set("elapsedBeforePause", 0);
    context.set("qfCounter", 0);
    context.set("nextDueMs", 0);
    context.set("lastFrameIndex", -1);
    context.set("cachedNibbles", null);

    global.set(zoneTC, "Stopped");
    global.set(zoneTrigTC, "stop");
    global.set(timecodeName, initial);
    global.set(framesZone, 0);
    global.set(msName, 0);

    const d = new Date(baseYear, baseMonth, baseDay, 0, 0, 0, 0);
    global.set(timestampName, d.getTime());
}

// ===================================================
//  INIT + INCOMING CONTROL
// ===================================================

if (context.get("initialized") !== true) {
    context.set("initialized", true);
    if (global.get(zoneTC) == null) global.set(zoneTC, "Stopped");
    if (global.get(zoneTrigTC) == null) global.set(zoneTrigTC, "stop");
    if (global.get(timecodeName) == null) global.set(timecodeName, initial);
    if (global.get(framesZone) == null) global.set(framesZone, 0);
    if (global.get(msName) == null) global.set(msName, 0);
    if (global.get(timestampName) == null) {
        const d = new Date(baseYear, baseMonth, baseDay, 0, 0, 0, 0);
        global.set(timestampName, d.getTime());
    }
}

// Parse command — handle both string "goto" and object {command:"goto", goto:0, ...}
let cmd = "";
let gotoTarget;

if (typeof msg.payload === "string") {
    cmd = msg.payload.toLowerCase();
    // Check msg.gotoMs passed from parse node (race-safe)
    if (msg.gotoMs !== undefined) {
        gotoTarget = Number(msg.gotoMs);
    }
} else if (msg.payload && typeof msg.payload === "object" && msg.payload.command) {
