    if (msg.payload.goto !== undefined) {
        gotoTarget = Number(msg.payload.goto);
    }
} else {
    //node.warn(cueListName + " unrecognized payload: " + JSON.stringify(msg.payload));
}

if (cmd === "goto") {
    // gotoTarget from message is race-safe; global fallback only for flow restart
    const targetMs = (gotoTarget !== undefined) ? gotoTarget : (Number(global.get(msName)) || 0);
    //node.warn(cueListName + " GOTO targetMs=" + targetMs + " (from " + (gotoTarget !== undefined ? "msg" : "global") + ") running=" + context.get("running"));
    stopGenerator();
    startOrResume(targetMs);
} else if (cmd === "start" && !context.get("running")) {
    startOrResume();
} else if (cmd === "start" && context.get("running")) {
    //node.warn(cueListName + " START ignored — already running");
} else if (cmd === "pause" && context.get("running")) {
    pauseGenerator();
} else if (cmd === "stop") {
    stopGenerator();
} else if (cmd !== "") {
    //node.warn(cueListName + " unknown cmd: " + cmd);
}

return null;

